export type OrganizationSource = "open-info" | "tatar-congress";
export type OrganizationCategory = "open-info" | "russian-federation-regions" | "foreign-organizations";

export interface OrganizationLink {
  type: string;
  url: string;
  label: string;
}

export interface OrganizationLocation {
  flag: string;
  city: string;
  country: string;
  region?: string;
  address?: string;
}

export interface OrganizationContacts {
  leader: string;
  emails: string[];
  phones: string[];
}

export interface OrganizationRegistry {
  ogrn?: string;
  fullName?: string;
  shortName?: string;
}

export interface OrganizationMeta {
  pubDate?: string;
}

export interface OrganizationEntry {
  id: string;
  name: string;
  type: string;
  category: OrganizationCategory;
  source: OrganizationSource;
  summary: string;
  description: string;
  location: OrganizationLocation;
  contacts: OrganizationContacts;
  links: OrganizationLink[];
  registry?: OrganizationRegistry;
  meta?: OrganizationMeta;
}

export interface OrganizationCountryGroup {
  country: string;
  flag: string;
  count: number;
  entries: OrganizationEntry[];
}

export interface OrganizationRegionGroup {
  region: string;
  flag: string;
  count: number;
  entries: OrganizationEntry[];
}

export interface OrganizationWorldRegionGroup {
  worldRegion: string;
  label: string;
  count: number;
  countries: OrganizationCountryGroup[];
  entries: OrganizationEntry[];
}

